# Import necessary libraries
from haystack.document_store.faiss import FAISSDocumentStore
from haystack.retriever.dense import DensePassageRetriever
from haystack.pipeline import DocumentSearchPipeline
import torch
from transformers import RagTokenizer, RagRetriever, RagTokenForGeneration

# Initialize tokenizer
tokenizer = RagTokenizer.from_pretrained('facebook/rag-token-nq')

# Load FAISS document store
document_store = FAISSDocumentStore(
    faiss_index_factory_str="Flat"
)

# Load documents into FAISS document store
documents = [...]  # Replace with your list of documents
for doc in documents:
    doc['_id'] = doc['title']  # Use title as id 
document_store.write_documents(documents)

# Initialize dense retriever
retriever = DensePassageRetriever(
    document_store=document_store,
    query_embedding_model="facebook/dpr-question_encoder-single-nq-base",
    passage_embedding_model="facebook/dpr-ctx_encoder-single-nq-base",
    use_gpu=True,
    embed_title=True,
)
document_store.update_embeddings(retriever)

# Initialize RAG retriever
rag_retriever = RagRetriever(
    document_store=document_store,
    index='encoded_documents',
    question_encoder_tokenizer=tokenizer.question_encoder,
    generator_tokenizer=tokenizer.generator,
)

# Initialize RAG model
model = RagTokenForGeneration.from_pretrained('facebook/rag-token-nq')
model = model.to('cuda') if torch.cuda.is_available() else model

# Initialize document search pipeline
pipeline = DocumentSearchPipeline(retriever=rag_retriever)

# Function to accept user queries
def get_answer(query: str):
    # Feed the user query into the pipeline
    output = pipeline.run(query=query)

    # Retrieve relevant context
    context = ' '.join([doc.meta['name'] for doc in output['documents']])
    
    # Include all retrieved documents in LLM prompt
    input_ids = tokenizer.encode(context, return_tensors='pt')

    # Generate answer from the model
    generated = model.generate(input_ids)
    answer = tokenizer.decode(generated[0])

    return answer

